mapper.select:

WHERE 
ORDER BY 


        (SELECT MIN(pv.price) FROM product_variants pv WHERE pv.product_id = p.id AND pv.deleted = 0)


        (SELECT MIN(pv.sale_price) FROM product_variants pv WHERE pv.product_id = p.id AND pv.deleted = 0)


        (SELECT pv.${sortBy} FROM product_variants pv WHERE pv.product_id = p.id AND pv.deleted = 0 LIMIT 1)


        p.${sortBy}


${sortDir}
LIMIT #{limit} OFFSET #{offset}



    AND (p.name LIKE CONCAT('%', #{keyword}, '%')
             OR p.description LIKE CONCAT('%', #{keyword}, '%')
             OR p.brand LIKE CONCAT('%', #{keyword}, '%'))


        AND p.category_id = #{categoryId}


        AND p.brand LIKE CONCAT('%', #{brand}, '%')


        AND EXISTS (
            SELECT 1 FROM product_variants pv WHERE pv.product_id = p.id AND pv.deleted = 0
            AND pv.cpu LIKE CONCAT('%', #{cpu}, '%')
            AND pv.ram LIKE CONCAT('%', #{ram}, '%')
            AND pv.storage LIKE CONCAT('%', #{storage}, '%')
            AND pv.price >= #{minPrice}
            AND pv.price <= #{maxPrice}
        )

    AND p.deleted = 0

ORDER BY 


        (SELECT MIN(pv.price) FROM product_variants pv WHERE pv.product_id = p.id AND pv.deleted = 0)


        (SELECT MIN(pv.sale_price) FROM product_variants pv WHERE pv.product_id = p.id AND pv.deleted = 0)


        (SELECT pv.${sortBy} FROM product_variants pv WHERE pv.product_id = p.id AND pv.deleted = 0 LIMIT 1)


        p.${sortBy}


${sortDir}
LIMIT #{limit} OFFSET #{offset}
